import{_ as a,o,c as n,a3 as s}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"📦 资产管理器 - 快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/asset-manager/index.md","filePath":"user-guide/tools/asset-manager/index.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/asset-manager/index.md"};function l(e,t,i,d,h,p){return o(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="📦-资产管理器-快速上手" tabindex="-1">📦 资产管理器 - 快速上手 <a class="header-anchor" href="#📦-资产管理器-快速上手" aria-label="Permalink to &quot;📦 资产管理器 - 快速上手&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>资产管理器是应用的<strong>中央资产仓库</strong>，所有工具（如 LLM 聊天、智能 OCR、媒体生成器等）导入的文件都会统一存储在这里。你可以把它理解为应用的&quot;资源管理器&quot;——浏览、搜索、预览和管理所有已导入的图片、视频、音频和文档。</p><blockquote><p><strong>核心特性：统一存储，跨工具复用。</strong> 你在聊天中上传的图片、OCR 扫描的文档、智能生成的媒体文件，都会被集中管理，随时可查，无需重复导入。</p></blockquote><div class="tip custom-block"><p class="custom-block-title">核心场景</p><ul><li>想回顾之前聊天中上传的某张图片</li><li>批量清理不再需要的导入文件</li><li>查看每个资源的来源信息，追溯&quot;这个文件是哪来的&quot;</li><li>发现重复文件并释放磁盘空间</li></ul></div><h3 id="资产类型" tabindex="-1">资产类型 <a class="header-anchor" href="#资产类型" aria-label="Permalink to &quot;资产类型&quot;">​</a></h3><p>资产管理器支持以下五种资产类型：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>预览方式</th></tr></thead><tbody><tr><td><strong>图片</strong></td><td>PNG / JPG / WebP / GIF 等</td><td>内置图片查看器（缩放、旋转、翻页）</td></tr><tr><td><strong>视频</strong></td><td>MP4 / WebM / AVI 等</td><td>内置视频播放器（倍速、画中画）</td></tr><tr><td><strong>音频</strong></td><td>MP3 / FLAC / WAV / OGG 等</td><td>内置音频播放器（播放列表）</td></tr><tr><td><strong>文档</strong></td><td>PDF / TXT / Markdown / 代码等</td><td>文档预览器（源码/渲染切换）</td></tr><tr><td><strong>其他</strong></td><td>未分类的文件格式</td><td>暂不支持预览</td></tr></tbody></table><h2 id="导入资产" tabindex="-1">导入资产 <a class="header-anchor" href="#导入资产" aria-label="Permalink to &quot;导入资产&quot;">​</a></h2><p>资产管理器本身不提供独立的上传入口——资产是通过各个工具的使用过程中<strong>自动导入</strong>的。</p><h3 id="方式一-拖放文件到应用窗口" tabindex="-1">方式一：拖放文件到应用窗口 <a class="header-anchor" href="#方式一-拖放文件到应用窗口" aria-label="Permalink to &quot;方式一：拖放文件到应用窗口&quot;">​</a></h3><p>任意支持文件拖放的工具（如 LLM 聊天、媒体生成器等），将文件从系统文件管理器拖拽到应用窗口，文件会自动导入资产库。</p><h3 id="方式二-粘贴剪贴板内容" tabindex="-1">方式二：粘贴剪贴板内容 <a class="header-anchor" href="#方式二-粘贴剪贴板内容" aria-label="Permalink to &quot;方式二：粘贴剪贴板内容&quot;">​</a></h3><p>复制图片或文件后，切换到 LLM 聊天等工具，使用 <code>Ctrl + V</code>（或 <code>Cmd + V</code>）粘贴，文件会自动导入。</p><h3 id="方式三-工具自动生成" tabindex="-1">方式三：工具自动生成 <a class="header-anchor" href="#方式三-工具自动生成" aria-label="Permalink to &quot;方式三：工具自动生成&quot;">​</a></h3><p>部分工具会自动生成资产并存入资产库：</p><ul><li><strong>LLM 聊天</strong> — 聊天中上传或生成的图片</li><li><strong>智能 OCR</strong> — 扫描识别后保存的文档</li><li><strong>媒体生成器</strong> — AI 生成的图片和视频</li></ul><blockquote><p>TODO: 截图 - 展示 LLM 聊天中上传文件后的资产自动出现在资产库中</p></blockquote><h2 id="浏览资产库" tabindex="-1">浏览资产库 <a class="header-anchor" href="#浏览资产库" aria-label="Permalink to &quot;浏览资产库&quot;">​</a></h2><h3 id="界面布局" tabindex="-1">界面布局 <a class="header-anchor" href="#界面布局" aria-label="Permalink to &quot;界面布局&quot;">​</a></h3><p>资产管理器采用经典的三段式布局：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  工具栏：搜索、排序、分组、视图切换、文件操作  │</span></span>
<span class="line"><span>├──────────┬──────────────────────────────────┤</span></span>
<span class="line"><span>│          │                                  │</span></span>
<span class="line"><span>│  侧边栏   │      主视图（网格/列表）          │</span></span>
<span class="line"><span>│          │                                  │</span></span>
<span class="line"><span>│  资产统计 │      资产卡片/表格               │</span></span>
<span class="line"><span>│  类型筛选 │                                  │</span></span>
<span class="line"><span>│  来源筛选 │      （无限滚动加载）             │</span></span>
<span class="line"><span>│  模块筛选 │                                  │</span></span>
<span class="line"><span>│          │                                  │</span></span>
<span class="line"><span>└──────────┴──────────────────────────────────┘</span></span></code></pre></div><blockquote><p>TODO: 截图 - 资产管理器完整界面，标注各区域</p></blockquote><h4 id="资产统计-侧边栏" tabindex="-1">资产统计 (侧边栏) <a class="header-anchor" href="#资产统计-侧边栏" aria-label="Permalink to &quot;资产统计 (侧边栏)&quot;">​</a></h4><p>侧边栏顶部实时显示当前资产库的：</p><ul><li><strong>总数量</strong>：所有已导入文件的总个数。</li><li><strong>总大小</strong>：所有资产占用的总磁盘空间。</li></ul><h3 id="切换视图模式" tabindex="-1">切换视图模式 <a class="header-anchor" href="#切换视图模式" aria-label="Permalink to &quot;切换视图模式&quot;">​</a></h3><p>工具栏右侧提供了两种视图模式：</p><ul><li><strong>网格视图</strong> — 卡片式展示，适合浏览图片等视觉类资产</li><li><strong>列表视图</strong> — 表格形式展示，包含文件名、类型、大小、来源、导入时间等详细信息</li></ul><p>网格视图下还可以调整卡片尺寸：<strong>大卡片</strong> / <strong>中卡片</strong> / <strong>小卡片</strong>。</p><h3 id="分组浏览" tabindex="-1">分组浏览 <a class="header-anchor" href="#分组浏览" aria-label="Permalink to &quot;分组浏览&quot;">​</a></h3><p>通过工具栏的&quot;分组&quot;下拉菜单，可以按不同维度组织资产：</p><table tabindex="0"><thead><tr><th>分组方式</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><strong>按月份</strong></td><td>按导入月份分组</td><td>2025年03月、2025年02月...</td></tr><tr><td><strong>按类型</strong></td><td>按文件类型分组</td><td>图片、视频、音频、文档...</td></tr><tr><td><strong>按来源</strong></td><td>按导入方式分组</td><td>本地文件、剪贴板、网络、AI 生成...</td></tr><tr><td><strong>按来源模块</strong></td><td>按来源工具分组</td><td>LLM 聊天、智能 OCR...</td></tr><tr><td><strong>不分组</strong></td><td>平铺展示所有资产</td><td>—</td></tr></tbody></table><h3 id="排序方式" tabindex="-1">排序方式 <a class="header-anchor" href="#排序方式" aria-label="Permalink to &quot;排序方式&quot;">​</a></h3><p>工具栏支持多种排序维度，帮助你快速定位文件：</p><ul><li><strong>按时间</strong> (默认)：按导入时间倒序排列，最新的文件在前。</li><li><strong>按名称</strong>：按文件名的字母顺序排列。</li><li><strong>按大小</strong>：按文件体积大小排列。</li></ul><h3 id="搜索与筛选" tabindex="-1">搜索与筛选 <a class="header-anchor" href="#搜索与筛选" aria-label="Permalink to &quot;搜索与筛选&quot;">​</a></h3><ul><li><strong>关键词搜索</strong> — 在工具栏的搜索框中输入文件名关键词，实时过滤</li><li><strong>侧边栏筛选</strong> — 可按文件类型、来源方式、来源模块进行精确筛选</li><li><strong>组合筛选</strong> — 搜索关键词与多种筛选条件可叠加使用</li></ul><blockquote><p>TODO: 截图 - 展示搜索框输入关键词后列表实时过滤的效果</p></blockquote><h2 id="基本操作" tabindex="-1">基本操作 <a class="header-anchor" href="#基本操作" aria-label="Permalink to &quot;基本操作&quot;">​</a></h2><h3 id="查看和预览资产" tabindex="-1">查看和预览资产 <a class="header-anchor" href="#查看和预览资产" aria-label="Permalink to &quot;查看和预览资产&quot;">​</a></h3><ul><li><strong>图片</strong>：单击预览，在图片查看器中缩放、旋转，支持同组图片翻页浏览</li><li><strong>视频</strong>：单击打开视频播放器，支持倍速播放、画中画、截图</li><li><strong>音频</strong>：单击开始播放，支持播放列表顺序切换</li><li><strong>文档</strong>：单击在弹窗中预览，支持源码/渲染模式切换</li></ul><h3 id="多选操作" tabindex="-1">多选操作 <a class="header-anchor" href="#多选操作" aria-label="Permalink to &quot;多选操作&quot;">​</a></h3><p>资产卡片/行支持多选：</p><ul><li><strong>单击</strong>：选中/取消单个资产</li><li><strong><code>Ctrl + 单击</code>（或 <code>Cmd + 单击</code>）</strong>：切换单个资产的选中状态</li><li><strong><code>Shift + 单击</code></strong>：范围选中连续资产</li></ul><p>选中资产后，工具栏会显示&quot;删除选中&quot;和&quot;取消选择&quot;按钮。</p><h3 id="文件操作-高级功能" tabindex="-1">文件操作 (高级功能) <a class="header-anchor" href="#文件操作-高级功能" aria-label="Permalink to &quot;文件操作 (高级功能)&quot;">​</a></h3><p>工具栏左侧的 <strong>文件操作</strong> 下拉菜单提供了一些维护资产库的进阶工具：</p><ul><li><strong>查找重复文件</strong>：扫描全库，识别内容完全相同（哈希一致）的文件。发现重复后，界面上会高亮标记重复资产。</li><li><strong>自动选中副本</strong>：在发现重复文件后，此功能会自动选中那些“多余”的副本（保留每组中最新的一份），方便你一键清理。</li><li><strong>清除重复标记</strong>：取消界面上的重复高亮显示。</li><li><strong>重建索引</strong>：如果发现资产列表显示异常或搜索不准确，可以使用此功能重新扫描元数据并重建查询索引。</li></ul><h3 id="操作菜单" tabindex="-1">操作菜单 <a class="header-anchor" href="#操作菜单" aria-label="Permalink to &quot;操作菜单&quot;">​</a></h3><p>每个资产卡片或行都提供操作菜单（点击右上角的 <code>···</code> 按钮）：</p><ul><li><strong>预览</strong> — 打开对应的内置查看器（图片、视频、音频或文档）</li><li><strong>打开所在目录</strong> — 在系统文件管理器中定位原始文件</li><li><strong>删除</strong> — 将该资产从库中移除并移动到系统回收站</li></ul><blockquote><p>TODO: 截图 - 资产的右键菜单</p></blockquote><h3 id="删除资产" tabindex="-1">删除资产 <a class="header-anchor" href="#删除资产" aria-label="Permalink to &quot;删除资产&quot;">​</a></h3><p>支持单个删除和批量删除：</p><ol><li>选中要删除的资产（可多选）</li><li>点击工具栏的 <strong>删除选中</strong> 按钮</li><li>确认删除操作</li><li>文件会被移至系统回收站（可恢复）</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>删除资产会同时删除对应的原始文件。在确认删除前，请确保文件不再需要。</p></div><h3 id="打开文件所在目录" tabindex="-1">打开文件所在目录 <a class="header-anchor" href="#打开文件所在目录" aria-label="Permalink to &quot;打开文件所在目录&quot;">​</a></h3><p>右键资产 → <strong>打开所在目录</strong>，系统会打开文件资源管理器并定位到该资产的实际存储位置，方便将文件复制到其他地方使用。</p><h2 id="进一步阅读" tabindex="-1">进一步阅读 <a class="header-anchor" href="#进一步阅读" aria-label="Permalink to &quot;进一步阅读&quot;">​</a></h2><ul><li><a href="./source-tracking">来源追踪</a> — 了解如何追溯资产的来源信息</li><li><a href="./thumbnails-batch">缩略图管理</a> — 掌握缩略图的生成、格式设置和批量操作</li></ul>`,61)])])}const g=a(r,[["render",l]]);export{u as __pageData,g as default};
